import{_ as a,a as i,b as p,c as e,d as r,e as g,f as t,g as n}from"./image-20240118152858464-83bd3d4c.js";import{_ as d,a as o,b as s,c as h,d as c,e as f}from"./image-20240119231728162-6e03447d.js";import{_ as m,a as l,b as u,c as _,d as b,e as x,f as y,g as z,h as k,i as v,j as B,k as j,l as E}from"./image-20240123223643418-87e15607.js";import{_ as N,a as S,b as V,c as X,d as Y,e as Z,f as q}from"./image-20240124004540283-4fbdfbbb.js";import{_ as w,a as A,b as C,c as D,d as F,e as G,f as H,g as I,h as J}from"./image-20240126004601947-a28d9172.js";import{_ as K}from"./plugin-vue_export-helper-c27b6911.js";import{o as L,c as M,e as O}from"./app-cdce9db9.js";const P={},Q=O('<h1 id="读书总结" tabindex="-1"><a class="header-anchor" href="#读书总结" aria-hidden="true">#</a> 读书总结</h1><h2 id="绘制蜡烛图" tabindex="-1"><a class="header-anchor" href="#绘制蜡烛图" aria-hidden="true">#</a> 绘制蜡烛图</h2><figure><img src="'+a+'" alt="image-20240117145421606" tabindex="0" loading="lazy"><figcaption>image-20240117145421606</figcaption></figure><p>在绘制日线图的时候，每根图线需要开市价、最高价、最低价和收市价四种价格。线图的图线主要由若干竖直的线段组成，它们表示了各个对应时间段的最高价和最低价之间的范围。从每根竖直线段上，向左伸出一小段横线头，表示对应时间段内的开市价(最初价)。从每根图线上向右伸出一小段横线头，代表对应时间段内的收市价(最后价)。</p><p>在蜡烛图的图线内部，有一段胖鼓鼓的部分，称为实体。它表示了相应交易日的开市价与收市价之间的价格范围。如果实体是黑色的(即，将之涂满黑色)，则代表当日的收市价低于开市价。如果实体是白色的(即，将它保留为空白)，则表示当日收市价高于开市价。</p><p>在实体的上方和下方，各有一条瘦瘦的竖直线段，称为影线。这两条影线分别表示当日市场曾经向上和向下运动的极端价格。实体上方的影线称为上影线。实体下方的影线称为下影线。相应地，上影线的顶端代表了当日的最高价，下影线的底端代表了当日的最低价。</p><p>如果某根蜡烛图线没有上影线，那么这就是所谓的秃头蜡烛线。</p><p>如果某根蜡烛线没有下影线，那么它就是所谓的秃脚蜡烛线。</p><figure><img src="'+i+'" alt="image-20240117150847941" tabindex="0" loading="lazy"><figcaption>image-20240117150847941</figcaption></figure><p>图3.4是一根具有长长的黑色实体的蜡烛线，它表示市场的开市价接近当日最高价，收市价接近当日最低价，这是一段疲弱的行情。</p><p>图3.5与图3.4恰好相反，因此，它表示的是一段坚挺的行情，当日的价格波动幅度很大，而且开市价接近最低价，收市价接近最高价。</p><p>图3.6所示的蜡烛图线的实体较短，说明熊方与牛方正处于胶着状态，一时难分高下，这类蜡烛线称为纺锤线。</p><p>图3.7中的蜡烛图线甚至没有实体。在这种极端情况下，蜡烛线的实体实际上缩小为一根水平的横线了，就成为了十字线。</p><h2 id="反转形态" tabindex="-1"><a class="header-anchor" href="#反转形态" aria-hidden="true">#</a> 反转形态</h2><figure><img src="'+p+'" alt="image-20240117160318187" tabindex="0" loading="lazy"><figcaption>image-20240117160318187</figcaption></figure><p>趋势反转信号的出现,意味着之前的市场趋势可能发生变化,但是市场并不一定就此逆转到相反的方向上。</p><p><strong>重要原则:仅当反转信号所指的方向与市场的主要趋势方向一致时,我们才可以依据这个反转信号来开立新头寸。</strong></p><h3 id="锤子线和上吊线" tabindex="-1"><a class="header-anchor" href="#锤子线和上吊线" aria-hidden="true">#</a> 锤子线和上吊线</h3><figure><img src="'+e+'" alt="image-20240117161341671" tabindex="0" loading="lazy"><figcaption>image-20240117161341671</figcaption></figure><p>锤子线、上吊线：它们下影线较长，实体较小，在其全天价格区间里，实体处在接近顶端的位置上。在下降趋势中，它可能是下降趋势即将结束的信号，这种蜡烛线称为锤子线。如果出现在上涨行情之后，表明之前的市场运动也许已经结束，这类蜡烛线称为上吊线。</p><p><strong>判别标识：</strong></p><p>1.实体处于整个价格区间的上端，而实体本身的颜色是无所谓的。</p><p>2.下影线的长度至少达到实体高度的2倍。</p><p>3.在这类蜡烛线中，应当没有上影线，即使有上影线，其长度也是极短的。</p><p>看涨的锤子线或者看跌的上吊线，其下影线越长、上影线越短、实体越小，这类蜡烛线就越有意义。如果锤子线的实体是白色的，看涨的意义更强；如果上吊线的实体是黑的，其看跌的意义更强。</p><p><strong>当上吊线出现时，一定要等待其它看跌信号的证实，这一点特别重要。</strong></p><p><strong>上吊线验证原则：</strong></p><p>1.上吊线的实体与上吊线次日的开市价之间向下的缺口越大，那么上吊线就越有可能构成市场的顶部。</p><p>2.在上吊线之后，如果市场形成了一条黑色的实体，并且它的收市价低于上吊线的收市价，这也可以看作上吊线成立的一种佐证。</p><p><strong>实战经验：</strong></p><p>1.有时候蜡烛线不是理想的上吊线，比如下影线未达到实体高度的2倍，但是次日蜡烛线构成了它的验证信号，所以认为它还是成立的。</p><p>2.<strong>只有把价格形态与它之前的价格变化相结合，进行通盘的考虑，才能准确把握价格形态的意义。</strong></p><p>3.当锤子线出现的时候也可以等一等验证信号，比如再出现一跟白色的蜡烛线，并且收市价格高于锤子线的收市价格，那么这个跟蜡烛线可以看作是一个验证信号。</p><p>4.锤子线属于底部反转形态。在锤子线的判别准则中，其中有一条是，在锤子线之前，必定先有一段下降趋势（哪怕是较小规模的下降趋势），这样锤子线才能够逆转这个趋势。同样上吊线必须出现在一段上升趋势之后。</p><h3 id="吞没形态-抱线形态" tabindex="-1"><a class="header-anchor" href="#吞没形态-抱线形态" aria-hidden="true">#</a> 吞没形态(抱线形态）</h3><figure><img src="'+r+'" alt="image-20240117234413359" tabindex="0" loading="lazy"><figcaption>image-20240117234413359</figcaption></figure><p>吞没形态属于主要<strong>反转形态</strong>，是由两根颜色相反的蜡烛线实体所构成的。</p><p><strong>判别标准：</strong></p><p>1.在吞没形态之前，市场必须处在清晰可辨的上升趋势或下降趋势中，哪怕这个趋势只是短期的。</p><p>2.吞没形态必须由2条蜡烛线组成。其中第二根蜡烛线的实体必须覆盖第一根蜡烛线的实体（但是不一定需要吞没前者的上下影线）。</p><p>3.吞没形态的第二个实体必须与第一个实体的颜色相反。</p><p>第3条标准有例外的情况，条件是第一条蜡烛线的实体的必须非常小，小得几乎构成了一根十字线（或者它就是一根十字线）。如此一来，如果在长期的下降趋势之后，一个小小的白色实体为一个巨大的白色实体所吞没，那么也可能构成了底部反转形态。反之，在上升趋势中，如果一个小小的黑色实体为一个巨大的黑色实体所吞没，那么也可能构成了顶部反转形态。</p><p><strong>增强反转信号的特征：</strong></p><p>1.在吞没形态中，第一天的实体非常小，而第二天的实体非常大。说明原有趋势的驱动力正在消退，新趋势的潜在力量正在壮大。</p><p>2.吞没形态出现在超长期的或非常急剧的市场运动之后。如果存在超长期的上升趋势，则增加了以下这种可能性：潜在的买家已经入市买进，持有多头。在这种情况下，市场可能缺少足够的新的多头头寸的供应，无力继续推动市场上升。如果存在非常急剧的市场运动，则市场可能已经朝一个方向走得太远，容易遭受获利平仓头寸的打击。</p><p>3.在吞没形态中，第二个实体伴有超额的交易量。这种情形可能属于胀爆现象。</p><p>4.在吞没形态中，第二天的实体向前吞没的实体不止一个。</p><p><strong>实战经验：</strong></p><p>1.分析蜡烛图要有一定程度的灵活性，有时候第二个实体超过第一个实体的幅度很小，不是理想的吞没形态，这时要考虑当前市场是否比较疲软等。如果因为不是理想形态排除吞没形态的可能性，是非常危险的。</p><p>2.看涨吞没形态属于底部反转信号，出现在下降趋势之后或者横向交易区间的下边界才是有意义的。其它情况通常无意义。</p><h3 id="乌云盖顶形态-乌云线形态" tabindex="-1"><a class="header-anchor" href="#乌云盖顶形态-乌云线形态" aria-hidden="true">#</a> 乌云盖顶形态(乌云线形态)</h3><figure><img src="'+g+'" alt="image-20240118141328278" tabindex="0" loading="lazy"><figcaption>image-20240118141328278</figcaption></figure><p>乌云盖顶形态属于顶部反转形态，一般出现在上升趋势之后，也可能出现在水平调整区间的顶部。</p><p><strong>判别标准：</strong></p><p>1.第一天是一根坚挺的白色实体；</p><p>2.第二天的开市价格超过了第一天的最高价（这就是说超过了第一天的上影线的顶端）</p><p>3.第二天收市价格接近当日的最低价的水平，并且收市价明显地向下扎入到第一天白色实体的内部</p><p><strong>增强反转信号的特征：</strong></p><p>1.该形态中，黑色实体的收市价向下穿入前一个白色实体的程度越深，则该形态构成市场顶部的机会越大。如果黑色实体覆盖了前一天的整个白色实体，那就形成了看跌吞没形态。有些日本技术分析师要求，第二天黑色实体的收市价必须向下穿过前一天白色实体的50%。如果黑色实体的收市价没有向下穿过白色蜡烛线的中点，那么，当这类乌云盖顶形态发生后，或许我们最好等一等，看看是否还有进一步的看跌验证信号。如果在乌云盖顶形态之后，或者在看跌吞没形态之后，出现了一根长长的白色实体，而且其收市价超过了这两种形态的最高价，那么这可能预示着新一轮上冲行情的到来。</p><p>2.乌云盖顶形态发生在一个超长期的上升趋势中，它的第一天是一根坚挺的白色实体，其开市价就是最低价（就是说，是秃脚的），而且其收市价就是最高价（就是说，是秃头的）；它的第二天是一根长长的黑色实体，其开市价位于最高价，而且收市价位于最低价{这是一个秃头秃脚黑色蜡烛线）。</p><p>3.在乌云盖顶形态中，如果第二个实体（即黑色的实体）的开市价高于某个重要的阻挡水平，但是市场未能成功地坚守住，那么可能证明牛方已经无力控制市场了。</p><p>4.如果在第二天开市的时候，市场的交易量非常大，那么这里就可能发生胀爆现象。</p><p><strong>实战经验:</strong></p><p>1.有时候第二天的开市价格与前一日最高价格一致，而不是超过，该形态足以构成警告信号，应当把它视为一项负面因素。</p><p>2.在技术分析中，有一条基本的定理：原先的支撑水平一旦被突破，则转化为新的阻挡水平。</p><h3 id="刺透形态-斩回线形态" tabindex="-1"><a class="header-anchor" href="#刺透形态-斩回线形态" aria-hidden="true">#</a> 刺透形态(斩回线形态)</h3><figure><img src="'+t+'" alt="image-20240118151301529" tabindex="0" loading="lazy"><figcaption>image-20240118151301529</figcaption></figure><p>刺透形态（或者说斩回线形态）是与乌云盖顶形态相反的形态，出现在下跌的市场上，是底部反转信号。</p><p><strong>判别标准：</strong></p><p>1.第一根蜡烛线具有黑色实体</p><p>2.第二根蜡烛线则具有长长的白色实体</p><p>3.第二天开市价低于前一天的最低价格，收市价格向上超越了前一天的黑色实体的中点。</p><p><strong>增强反转信号的特征：</strong></p><p>1.在刺透形态中，白色实体向上刺入黑色实体的程度越大，该形态构成底部反转信号的可能性就越大。在看涨吞没形态之后，或者在看涨的刺透形态之后，如果跟着出现了一条长长的黑色蜡烛线，并且它的收市价低于上述两种形态的最低点，则说明下降趋势已经卷土重来，新一轮下跌行情开始了。</p><p>2.其它特征同乌云盖顶形态，而方向相反。</p><p><strong>实战经验：</strong></p><p>1.在讲述乌云盖顶的时候，有些日本交易商更愿意看到黑色实体的收市价向下穿过了前一个白色实体的中点，在这一条判别准则上，还是有一定的灵活余地的。然而，在斩新回线形态中，却没有任何灵活的余地。<strong>在斩回线形态中，白色蜡烛线的实体必须向上推进到黑色蜡烛线实体的中点之上。之所以看涨的刺透形态不如乌云盖顶形态灵活，是因为日本人认为处理底部反转形态必须更加谨慎。</strong></p><figure><img src="'+n+'" alt="image-20240118152858464" tabindex="0" loading="lazy"><figcaption>image-20240118152858464</figcaption></figure><p>2.这三种形态虽然与刺透形态在基本构造上是相似的，但是，正是由于其中的白色实体向上穿入黑色实体的程度达不到黑色实体的中点，它们被看作是看跌的信号。</p><p>3.图4.32所示的插入线形态如果处在下跌行情中，是看跌的，但是，如果它处在上升行情中，则应该视为看涨信号。另外，在下跌行情中，如果市场在数天之内接连形成了两个插入线形态，那么，这种情况也属于看涨信号。</p><h2 id="星线" tabindex="-1"><a class="header-anchor" href="#星线" aria-hidden="true">#</a> 星线</h2><figure><img src="'+d+'" alt="image-20240118213524120" tabindex="0" loading="lazy"><figcaption>image-20240118213524120</figcaption></figure><p>星蜡烛线（简称星线）的实体较小，并且在它的实体与它前面的较大的蜡烛线的实体之间形成了价格跳空。星线本身的颜色并不重要。星线既可能出现在市场的顶部，也可能出现在市场的底部。如果星线的实体已经缩小为十字线，则称之为十字星线。当星线，尤其是十字星线出现时，就是一个<strong>警告信号</strong>，表明当前的趋势或许好景不长了。</p><h3 id="启明星形态" tabindex="-1"><a class="header-anchor" href="#启明星形态" aria-hidden="true">#</a> 启明星形态</h3><figure><img src="'+o+'" alt="image-20240118214053791" tabindex="0" loading="lazy"><figcaption>image-20240118214053791</figcaption></figure><p>启明星形态属于底部反转形态。在本形态中，先是一根长长的黑色实体，随后是一根小小的实体，并且在这两个实体之间形成了一个向下跳空（这两条蜡烛线组成了基本的星线形态）。第三天是一根白色实体，它明显地向上推进到了第一天的黑色实体之内。</p><p>**在理想的启明星形态中，中间蜡烛线（即星线）的实体，与它前、后两个实体之间均有价格跳空。**后面的那个价格跳空较为少见，不过，即使没有后面这个价格跳空，似乎也不会削减启明星形态的技术效力。</p><h3 id="黄昏星形态" tabindex="-1"><a class="header-anchor" href="#黄昏星形态" aria-hidden="true">#</a> 黄昏星形态</h3><figure><img src="'+s+'" alt="image-20240118214855016" tabindex="0" loading="lazy"><figcaption>image-20240118214855016</figcaption></figure><p>黄昏星与启明星相反，是顶部反转形态，只有出现在上升趋势之后，才能发挥其技术效力。黄昏星形态是由三根蜡烛线组成的。在前两根蜡烛线中，第一根是一根长长的白色实体，后一根是一根星线。第三根蜡烛线具有黑色实体，它剧烈地向下扎入第一天的白色实体的内部。</p><p>从原则上说，在黄昏星形态中，首先在第一根实体与第二根实体之间，应当形成价格跳空；然后在第二根实体与第三根实体之间，再形成另一个价格跳空。第二个价格跳空并不常见，不是必要条件。本形态的关键之处在于第三天的黑色实体向下穿入第一天的白色实体的深浅程度。</p><p><strong>实战经验：</strong></p><p>1.虽然黄昏星形态在上升趋势后更为重要，但是如果它处在横向巩固区间的顶部，在其它看跌信号得到确认的条件下，也可能具有重要意义。</p><p><strong>黄昏星形态或启明星形态增强反转信号的特征：</strong></p><p>1.如果在第一根蜡烛线的实体与星蜡烛线的实体之间存在价格跳空，并且在星线的实体与第三根蜡烛线的实体之间也存在价格跳空；</p><p>2.如果第三根蜡烛线的收市价深深地向下扎入第一根蜡烛线的实体之内；</p><p>3.如果第一根蜡烛线的交易量较轻，而第三根蜡烛线的交易量较重。这一点表明了原先趋势力量的衰减，新趋势力量的增长。</p><h3 id="十字启明星形态和十字黄昏星形态" tabindex="-1"><a class="header-anchor" href="#十字启明星形态和十字黄昏星形态" aria-hidden="true">#</a> 十字启明星形态和十字黄昏星形态</h3><figure><img src="'+h+'" alt="image-20240119005004660" tabindex="0" loading="lazy"><figcaption>image-20240119005004660</figcaption></figure><p>如果在上升趋势中出现了一根十字线，并且这根十字线与前一个实体之间形成了向上的价格跳空；或者在下降趋势中出现了一根十字线，并且这根十字线与前一个实体之间形成了向下的价格跳空，那么。这根十字线就称为十字星蜡烛线（简称十字星线）。十字星线的出现，构成了潜在的警告信号，表明市场的当前趋势已经易于发生变化了。在这根十字线之后的蜡烛线，应当构成趋势反转的验证信号。</p><p>在上升趋势中，如果在十字星线后跟随着一根长长的黑色实体，并且它的收市价深深地向下扎入十字星线之前的白色实体的内部，那么，这根黑色实体就构成了市场顶部反转过程的验证信号。这样的形态就称为十字黄昏星形态（如图5.13所示）。十字黄昏星形态是常规黄昏星形态的一种特殊形式。因为十字黄昏星形态包含了一根十字线，所以具有更重要的技术意义。如果在十字星线之后，是一根向上跳空的白色蜡烛线，那么这根十字星线的疲弱性质就不再成立了。</p><p>在下降趋势中，如果在一根黑色实体之后，跟随着一条十字星线，第三根蜡烛线是一根坚挺的白色蜡烛线，并且它的收市价显著地向上穿人第一根黑色实体之内，那么，该底部反转信号就得到了第三根蜡烛线的验证。这个三蜡烛线形态称为十字启明星形态（如图5.14所示）。这一类启明星形态能够构成有意义的市场底部过程。在下降趋势中，如果在十字星线之后出现的是一根黑色蜡烛线，并且这根黑色蜡烛线向下跳空到了十字星线之下，那么这根十字星线潜在的看涨意义就冰消瓦解了。</p><p>在十字星线出现后，我们必须等待下面一、二个时间单位的验证信号。</p><p>如果市场上出现了一根向上跳空的十字星线（就是说，该十字星线的下影线与前一根蜡烛线的上影线没有任何重叠之处），它的后面再跟着一条向下跳空的黑色蜡烛线，并且在这根黑色蜡烛线的上影线与十字星线的下影线之间也形成了价格跳空，那么，这根十字星线就构成了一个主要顶部反转信号。这种形态称为弃婴顶部形态（如图5.15所示）。</p><p>在下降趋势中，如果在一根十字星线的前后均发生了价格跳空（包括有关蜡烛线的上下影线也五不接触），那么这条十字星线就构成了一个主要底部形态。人们将这种形态称为弃婴底部形态（如图5.16所示）</p><p>实战经验：</p><p>1.十字星线的实体应当高于前一天的实体。但是股票市场的开市价大多可能与前一日的收市价基本一致，因此，在股票市场进行蜡烛线信号的研究时，价格跳空的问题上，应当允许有更大的自由度。</p><h3 id="流星形态" tabindex="-1"><a class="header-anchor" href="#流星形态" aria-hidden="true">#</a> 流星形态</h3><figure><img src="'+c+'" alt="image-20240119215913475" tabindex="0" loading="lazy"><figcaption>image-20240119215913475</figcaption></figure><p>流星形态的技术意义不如黄昏星形态强，通常不构成主要反转信号。它发出警告信号，表明市场顶部就在眼前。</p><p>在流星形态中，流星线具有较小的实体，实体处于其价格区间的下端，上影线较长。与所有的星蜡烛线一样，流星线实体的颜色并不重要。</p><p><strong>实战经验：</strong></p><p>1.在理想的流星形态中，流星线的实体与前一根蜡烛线的实体之间存在价格跳空。价格跳空并不是非有不可的。</p><p>2.该形态出现在上升趋势之后，或横向巩固区间的顶部才有意义。</p><p>3.价格形态并不一定要十全十美才能够发出有效的交易信号。在研究蜡烛图线和蜡烛图形态的时候，我们总是应当结合其它各方面的技术线索进行综合的判断，具体情况，具体分析。有时候流星的实体没有发生跳空，但是从它们所具备的流星形态的轮廓，以及它们自身的价格变化过程，结合它们所处的行情背景来看，它们就具有看跌的意义了。</p><h3 id="倒锤子线" tabindex="-1"><a class="header-anchor" href="#倒锤子线" aria-hidden="true">#</a> 倒锤子线</h3><figure><img src="'+f+'" alt="image-20240119231728162" tabindex="0" loading="lazy"><figcaption>image-20240119231728162</figcaption></figure><p>倒锤子线看上去与流星线颇为相象，它也具有较长的上影线，较小的实体，并且实体居于整个价格范围的下端。但是不同的是，流星线是一根顶部反转蜡烛线，而倒锤子线却是一根底部反转蜡烛线。如果倒锤子线出现在下降趋势之后，则构成一个看涨的蜡烛图形态，这一点与普通的锤子线如出一辙。</p><p>倒锤子线的验证信号：</p><ul><li>倒锤子线次目的开市价向上跳空，超过了倒锤子线的实体。向上跳空的距离越大，验证信号就越强烈。</li><li>倒锤子线次日是一根白色蜡烛线，并且它的价格均处在较高的水平。</li></ul><p><strong>实战经验：</strong></p><p>1.当倒锤子线出现后，必须等待下一个时间单位的看涨信号对它加以验证。</p><h2 id="其它反转形态" tabindex="-1"><a class="header-anchor" href="#其它反转形态" aria-hidden="true">#</a> 其它反转形态</h2><h3 id="孕线形态" tabindex="-1"><a class="header-anchor" href="#孕线形态" aria-hidden="true">#</a> 孕线形态</h3><figure><img src="'+m+'" alt="image-20240119233945566" tabindex="0" loading="lazy"><figcaption>image-20240119233945566</figcaption></figure><p>孕线形态与吞没形态相比，两根蜡烛线的顺序恰好颠倒过来。在吞没形态中，后面是一根长长的实体，它将前一个小实体覆盖进去了。而在孕线形态中，前一个是非常长的实体，它将后一个小实体包容起来。在吞没形态中，两根蜡烛线的实体的颜色应当互不相同。而在孕线形态中，这一点倒不是一项必要条件。在绝大多数情况下，孕线形态的两个实体的颜色也是不同的。</p><p>孕线形态的出现，预示着市场将同先前的趋势分道扬镳。孕线形态则不仅要求当日的开市价与收市价均处于前一日的较宽的开市价与收市价的范围之内（即前一日是一个较高的实体），而且要求当日的开市价与收市价之间的距离比较小（即这一天是一根较小的实体）。</p><p>实战经验：</p><p>1.在孕线形态中，两个实体的相对大小是至关重要的，而它们的影线的相互关系，则无须深究。</p><p>2.孕线形态的出现未必一定预示着市场的上涨。在孕线形态出现后，市场通常缓和下来，转化为横向整理区间。</p><p>3.作为一条普遍的经验，在孕线形态中，第二根实体越小，则整个形态越有力量</p><h3 id="十字孕线形态" tabindex="-1"><a class="header-anchor" href="#十字孕线形态" aria-hidden="true">#</a> 十字孕线形态</h3><figure><img src="'+l+'" alt="image-20240121163635453" tabindex="0" loading="lazy"><figcaption>image-20240121163635453</figcaption></figure><p>十字孕线形态，指的是在孕线形态中，第二天是一根十字线，而不是一个小实体。因为十字孕线形态包含了一根强有力的十字蜡烛线，所以这类形态被视为<strong>主要反转信号</strong>。十字孕线形态有时也称为呆滞形态。</p><p>一般的孕线形态并不属于主要反转形态，但是，十字孕线形态恰怡是一种主要反转形态。</p><h3 id="平头顶部形态和平头底部形态" tabindex="-1"><a class="header-anchor" href="#平头顶部形态和平头底部形态" aria-hidden="true">#</a> 平头顶部形态和平头底部形态</h3><p>平头形态是由具有几乎相同水平的最高点的两根蜡烛线组成的，或者是由具有几乎相同的最低点的二根蜡烛线组成的。之所以将这种形态称为平头形态，是因为这些蜡烛线的端点就像镊子腿一样平齐。</p><p>在上升的市场中，当几根蜡烛线的最高点不相上下时，就形成了一个平头顶部形态。在下降的市场上，当几根蜡烛线的最低点基本一致时，就形成了一个平头底部形态。平头形态既可以由实体构成，也可以由影线或者十字线构成。平头形态既可以由相邻的蜡烛线组成，也可以由相隔较近的蜡烛线组成。不过，在这种情况下，它通常不能成为一个决定性的反转形态。构成平头形态的蜡烛线也可能相距甚远，并且其中间夹着较长期的市场变化；或者在平头形态之内，同时包含着其它看跌的蜡烛图因素（在构成顶部反转信号时），或者同时包含着其它看涨的蜡烛图因素（在构成底部反转信号时）。在这样的情况下，平头形态就多了一些额外的技术分量。</p><figure><img src="'+u+'" alt="image-20240121165439699" tabindex="0" loading="lazy"><figcaption>image-20240121165439699</figcaption></figure><figure><img src="'+_+'" alt="image-20240121165447367" tabindex="0" loading="lazy"><figcaption>image-20240121165447367</figcaption></figure><p>如图6.13所示，在上升趋势中，先是一根长长的白色蜡烛线，后是一根十字线。这个二蜡烛线形态既是一个十字孕线形态，又是一个平头形态，因为这两根蜡烛线具有同样的最高点。综合来看，这个形态可能构成了重要的反转信号。如图6.14所示，在这个平头形态中，先是一根长长的白色蜡烛线，后是一根上吊线。下一天，如果市场开市于上吊线的实体之下，那么，把这个形态判断为一个顶部反转信号，就有了很大的胜算。只要市场的收市价不高于这个平头形态的顶部，那么这种看跌的态度就不可动摇。这个二蜡烛线的混合体也可以看做一个孕线形态。结合以上分析，这个孕线形态处于上升趋势中，构成了一个顶部反转形态。如图6.15所示，在这个平头顶部形态中，第二根蜡烛线同时又是一根看跌的流星线。尽管它不是一根真正的流星线，但是根据形成这根蜡烛线的价格变化过程，这根线本身是看跌的。在这根蜡烛线上，市场开市于最低点，然后上冲到前一天的最高价的水平，后来却收市于当日的最低点附近。另外，本形态还可以看成孕线形态。</p><p>如图6.16所示，是一个乌云盖顶形态的变体。在这个形态中，第二天的开市价高于第一天的收市价（而不是高于第一天的最高价）。黑色蜡烛线的最高点曾经触及前一天的最高点，而后市场再回落。这个形态既可以看做乌云盖顶形态，也可以看做平头顶部形态，是一个双重组合。如图6.17所示，在这里的二蜡烛线形态中，后一根为锤子线，并且它成功地向下试探了前一根长长的黑色蜡烛线的最低点。锤子线、市场对支撑水平的成功试探，两方面因素同时证明卖方已经丧失了对市场的控制。最后，这个二蜡烛线组合也可以视为孕线形态。这是将此处判断为一个重要支撑水平的第三条理由。如图6.18所示，为一个看涨刺透形态的变体，它同时还构成了一个平头底部形态。两者形成了一个有力的组合。在理想的刺透形态中，第二天的开市价低于第一天的最低点。但是在这个形态中，第二天的开市价仅低于第一天的收市价。</p><p>实战经验：</p><p>1.平头顶部形态和平头底部形态应当得到其它蜡烛图指标的验证，如此便能够上升为一种很有价值的预测工具。</p><p>2.于希望获得<strong>长期的市场看法</strong>的朋友来说，不妨选用<strong>周蜡烛线图和月蜡烛线图</strong>进行研究，在这种情况下，由相邻的蜡烛线形成的平头顶部形态和平头底部形态可能构成重要的反转信号。这类形态甚至在没有其它蜡烛图信号相验证的条件下，也是成立的。**在周蜡烛线图或月蜡烛图上，如果前一个时间单位的低点在后一个时间单位内成功地经受了市场向下的试探，这个低点就可能构成重要的市场底部，引发上冲行情。**在日蜡烛线图上，类似的情况可能就不那么重要了，因为今天成功地经受试探的不过是昨天的低点，演变成市场底部、引发上冲行情的可能性就不如上面的例子大。</p><h3 id="捉腰带线" tabindex="-1"><a class="header-anchor" href="#捉腰带线" aria-hidden="true">#</a> 捉腰带线</h3><figure><img src="'+b+'" alt="image-20240123204854080" tabindex="0" loading="lazy"><figcaption>image-20240123204854080</figcaption></figure><p>看涨捉腰带形态是一根坚挺的白色蜡烛线；其开市价位于当日的最低点（或者这根蜡烛线只有极短的下影线）。看涨捉腰带线又称为开盘秃（脚）阳线。如果市场处于低价区域，出现了一根长长的看涨捉腰带线，则预示着上冲行情的到来。</p><p>看跌捉腰带形态是一根长长的黑色蜡烛线，它的开市价位于当日的最高点（或者这根蜡烛线只有极短的上影线），在市场处于高价区的条件下，看跌捉腰带形态的出现，构成了顶部反转信号。看跌捉腰带线有时也称为开盘秃（头）阴线。</p><p><strong>增强信号：</strong></p><p>1.捉腰带蜡烛线的长度愈长，则该形态的技术意义越重大。</p><p>2.如果捉腰带线是在市场趋势已经发展了较长时间之后才出现的，那么它的意义也更加重要。</p><p>如果市场收市于黑色的看跌捉腰带线之上，则意味着上升趋势已经恢复。如果市场收市于白色的看涨捉腰带线之下，则意味着市场的抛售压力重新积聚起来了。</p><h3 id="向上跳空两只乌鸦" tabindex="-1"><a class="header-anchor" href="#向上跳空两只乌鸦" aria-hidden="true">#</a> 向上跳空两只乌鸦</h3><figure><img src="'+x+'" alt="image-20240123210630361" tabindex="0" loading="lazy"><figcaption>image-20240123210630361</figcaption></figure><p>如图6.30所示，为向上跳空二只乌鸦形态。“向上跳空”指的是图示的小黑色实体与它们之前的实体（即第一个小黑色实体之前的实体，通常是一根长长的白色实体）之间的价格跳空。这是一种看跌的价格形态。在理想的向上跳空两只乌鸦形态中，第二个黑色实体的开市价高于第一个黑色实体的开市价，并且它的收市价低于第一个黑色实体的收市价。</p><p>如图6.31所示，这种形态称为铺垫形态，铺垫形态发生在牛市行情中，是一种看涨的持续形态。在这个形态中，头三根蜡烛线与向上跳空二只乌鸦形态相似，但是此后，又跟了一根黑色蜡烛线。如果接下来的一根蜡烛线是白色的，并向上跳空，向上超过了上述最后一根黑色蜡烛线的上影线；或者这根白色蜡烛线的收市价高于最后一根黑色蜡烛线的最高价，则形成了买入信号。在铺垫形态中，可以有2根、3根乃至4根黑色蜡烛线。相对而言，向上跳空二只乌鸦形态和铺垫形态都是很少见的。</p><p>铺垫形态与向上跳空二只乌鸦形态主要的区别在于，在本形态最后，出现了一根白色的蜡烛线，使本形态摇身一变，成为一个看涨形态。</p><p>当向上跳空二只鸟鸦形态出现后，应当在该形态的第二根黑色蜡烛线的最高点上方设置止损保护指令，以防备市场收市于该水平之上。</p><h3 id="三只乌鸦" tabindex="-1"><a class="header-anchor" href="#三只乌鸦" aria-hidden="true">#</a> 三只乌鸦</h3><figure><img src="'+y+'" alt="image-20240123211739156" tabindex="0" loading="lazy"><figcaption>image-20240123211739156</figcaption></figure><p>连续出现了三根依次下降的黑色蜡烛线，则构成了所谓的三只乌鸦形态（图6.35所示）。如果三只乌鸦形态出现在高价格水平上，或者出现在经历了充分发展的上涨行情中，就预示着价格即将下跌。</p><p>从外形上说，这三根黑色蜡烛线的收市价都应当处于其最低点，或者接近其最低点；毎根黑色蜡烛线的开市价也都应该处于前一个实体的范围之内。另外，分析者可能还希望“三只乌鸦”中的第一根黑色蜡烛线的实体，居于它之前的那根白色蜡烛线的最高点以下。</p><h3 id="反击线形态-约会线形态" tabindex="-1"><a class="header-anchor" href="#反击线形态-约会线形态" aria-hidden="true">#</a> 反击线形态(约会线形态)</h3><figure><img src="'+z+'" alt="image-20240123212127611" tabindex="0" loading="lazy"><figcaption>image-20240123212127611</figcaption></figure><p>当两根颜色相反的蜡烛线具有相同的收市价时，就形成了一个反击线形态（也称为约会线形态）。</p><p>看涨反击形态与看涨刺透在形态上类似。它们之间主要的区别是，看涨反击线通常并不把收市价向上推进到前一天的白色实体的内部，而是仅仅回升到前一天的收市价的位置。而在刺透形态中，第二根蜡烛线深深地向上穿入了前一个黑色实体之内。因此，刺透形态与看涨反击线形态相比较，刺透形态是一种更为重要的底部反转信号。尽管如此，我们对看涨反击线形态还是不可小親的。</p><p>看跌反击线形态与乌云盖顶形态也有类似的关系。在看跌反击线形态中，第二天的开市价高于前一天的最高点，这一点与乌云盖顶形态是一致的。但是，与乌云盖顶形态不同的是，这一天的收市价并没有向下穿入前一天的白色蜡烛线之内。由此看来，乌云盖顶形态所发出的顶部反转信号，比看跌反击线形态更强。</p><p>在反击线形态中，一项重要的考虑因素是，第二天的开市价是否强劲地上升到较高的水平（在看跌反击线形态中），或者是否剧烈地下降到较低的水平（在看涨反击线形态中）。</p><h3 id="三山和三川形态" tabindex="-1"><a class="header-anchor" href="#三山和三川形态" aria-hidden="true">#</a> 三山和三川形态</h3><figure><img src="'+k+'" alt="image-20240123213532380" tabindex="0" loading="lazy"><figcaption>image-20240123213532380</figcaption></figure><p>如图6.44所示，为三山顶部形态。一般认为，本形态构成了一种主要顶部反转过程。如果市场先后三次均从同一个高价位上回落，或者市场对某一个高价位向上进行了三次尝试，但统统归于失败，那么就形成了一个三山顶部形态。<strong>在三山顶部形态的最后一座山的最高点，还应当出现某种看跌的蜡烛图指标（比如说，一根十字线，或者一个乌云盖顶形态等〉，以对三山顶部形态作出确认</strong>。</p><p>在三山顶部形态中，如果中间的山峰高于两侧的山峰，则构成了一种特殊的三山形态，称为三尊顶部形态（如图6.45所示）</p><figure><img src="'+v+'" alt="image-20240123220352263" tabindex="0" loading="lazy"><figcaption>image-20240123220352263</figcaption></figure><p>三川底部形态（如图6.46所示）怡巧是三尊顶部形态的反面。在市场先后三度向下试探某个底部水平后，就形成了这类形态。市场必须向上突破这个底部形态内的最高水平，才能证实底部过程已经完成。与西方的头肩形底部形态（也称为倒头肩形）对等的蜡烛图形态是变体三川底部形态，或者称为倒三尊形态（如图6.47所示）。</p><h3 id="圆形顶部形态和平底锅底部形态-圆形底部形态" tabindex="-1"><a class="header-anchor" href="#圆形顶部形态和平底锅底部形态-圆形底部形态" aria-hidden="true">#</a> 圆形顶部形态和平底锅底部形态(圆形底部形态)</h3><figure><img src="'+B+'" alt="image-20240123222422470" tabindex="0" loading="lazy"><figcaption>image-20240123222422470</figcaption></figure><p>在圆形顶部形态（如图6.53所示）中，市场逐步形成向上凸起的圆弧状图案，在这个过程中，通常出现的是一些较小的实体。最后，当市场向下跳空时，就证明圆形顶部形态巳经完成。<strong>在圆形顶部形态中，应当包含一个向下的窗口，作为市场顶部的验证信号。</strong></p><p>平底锅底部形态（即圆形底部形态，如图6.54所示）反映出市场正处于底部反转过程中，市场逐步呈现出向下凹进的圆弧状图案，然后市场打开一个向上的窗口，<strong>在日本的平底锅底部形态中，必须出现一个向上的窗口，以证实市场底部的完成。</strong></p><h3 id="塔形顶部形态和塔形底部形态" tabindex="-1"><a class="header-anchor" href="#塔形顶部形态和塔形底部形态" aria-hidden="true">#</a> 塔形顶部形态和塔形底部形态</h3><figure><img src="'+j+'" alt="image-20240123222920811" tabindex="0" loading="lazy"><figcaption>image-20240123222920811</figcaption></figure><p>塔形顶部形态属于顶部反转形态。市场本来处在上升趋势中，在某一时刻，出现了一根坚挺的白色蜡烛线（或者出现了一系列高高的白色蜡烛线）。后来，市场先是放缓了上涨的步调，然后，蜡烛线的高点开始下降。最后，市场上出现了一根或者数根长长的黑色蜡烛线，于是，塔形顶部形态就完成了（如图6.58所示）。在本形态中，两侧的长长的蜡烛线形似高塔--因此，它就得了这样的名称。</p><p>塔形底部形态发生在低价格水平上。市场在形成了一根或数根长长的黑色蜡烛线之后，经历了一阵短暂的平静。然后，出现了一根或数根长长的白色蜡烛线。这样就形成了一个塔形底部形态，它两侧的外形也像高塔一般（如图6.59所示）。这就是说，市场先以长长的蜡烛线一路而下，后来又以长长的蜡烛线一路而上。</p><h3 id="奇特三川底部形态" tabindex="-1"><a class="header-anchor" href="#奇特三川底部形态" aria-hidden="true">#</a> 奇特三川底部形态</h3><figure><img src="'+E+'" alt="image-20240123223643418" tabindex="0" loading="lazy"><figcaption>image-20240123223643418</figcaption></figure><p>在蜡烛图形态中，与这个形态关系最近的是启明星形态。</p><p>奇特三川底部形态属于底部反转信号。它的第一根蜡烛线是一根极长的黑色蜡烛线；第二根蜡烛线也是一根黑色实体的蜡烛线，其收市价高于第一根蜡烛线的收市价；第三根蜡烛线是一根具有很小的白色实体的蜡烛线。最后这根蜡烛线说明，市场的抛售压力已经消耗殆尽了。</p><h2 id="持续形态" tabindex="-1"><a class="header-anchor" href="#持续形态" aria-hidden="true">#</a> 持续形态</h2><h3 id="窗口" tabindex="-1"><a class="header-anchor" href="#窗口" aria-hidden="true">#</a> 窗口</h3><p>日本技术分析师一般把价格跳空称为窗口。按照西方的表达方式，我们说“回填跳空”；在日本，人们则说：“关上窗口。</p><figure><img src="'+N+'" alt="image-20240123224350488" tabindex="0" loading="lazy"><figcaption>image-20240123224350488</figcaption></figure><p>**所谓窗口，是指在前一根蜡烛线的端点与后一根蜡烛线的端点之间存在着一个价格缺口。**如图7.1所示，是在上升趋势中形成的一个“打开的”窗口。在图示的前一根蜡烛线的上影线与后一根蜡烛线的下影线之间，存在一段价格缺口。如图7.2所示，是下降趋势中的一个窗口。从中可以看到，在前一天的下影线和当日的上影线之间，未曾发生任何价格活动。</p><p><strong>根据日本技术分析师的观点，市场参与者应当顺者窗口形成的方向建立头寸。同时，窗口还将演化为支撑区或阻挡区。</strong></p><p>在上涨行情中，如果出现了一个窗口，则意味着价格将进一步上升。并且，今后当市场向下回撤时，这个窗口将形成其底部支撑水平。如果市场在向下回撤时关闭了这个窗口，并且在窗口关闭后，市场的抛售压力依然存在，那么，先前的上升趋势就不复成立了。类似地，在下跌的价格环境中，如果出现了一个窗口，则意味着市场还将进一步下降。此后形成的任何向上价格反弹，都会在这个窗口处遭遇阻挡。如果该窗口被关闭，并且在窗口关闭后，上涨行情继续发展，那么，原来的下降趋势就完结了。</p><p>传统的日本技术分析理论（也就是蜡烛图技术）确信，<strong>当一个窗口形成后，如果市场开始调整，那么，价格将回到该窗口处</strong>。换言之，市场很可能回头试探一个打开的窗口。因此，<strong>在上升趋势中，我们可以把窗口看作买进的参考点，乘市场回撤到这里时入市</strong>。另一方面，如果在窗口关闭后，市场的抛售压力仍然不消退的话，那么.就应当把多头头寸平仓出清，甚而可以考虑建立空头头寸。如果在下降趋势中出现了一个窗口，就应当采取与上述相反的对策。</p><p>实战经验：</p><p>1.窗口之后发生的市场回撤，将重新返回窗口。</p><p>2.从横向整固区间中跳起的窗口，以及从新高价位上跳起的窗口，值得特别注意。这个窗口就具备了双重的支撑作用。这种支撑作用首先来自该窗口本身，其次，因为这里过去是阻挡区，现在已经转化为支撑区了。</p><p>3.可能构成一个极有意义的向上突破信号，特别是当这个窗口是从较低的横向整理区间向上跳起，而且形成窗口的是一根小的黑色蜡烛线的时候。</p><p>4.市场最重要的三个方面是：趋势、趋势、趋势。蜡烛图信号与任何技术工具一样，必须在当前主要趋势的大前提下进行研究。</p><p>5.根据蜡烛图理论，在一段行情接连形成了8个到10个新高或者新低之后，如果市场还没有经过任何有意义的调整过程，那么，即将发生重大调整的可能性就非常大。</p><p>6.传统的日本技术分析理论断言：在一个趋势中，如果已经出现了3个向上的或向下的窗口（即所谓三空形态），那么，市场即将形成顶部（如果这三个窗口发生在上升趋势中）或底部（如果这三个窗口发生在下降趋势中）的机会是极大的；特别是在第三个窗口之后，如果出现了某种转折性的蜡烛图形态或蜡烛线（比如说十字线，刺透形态，或者乌云盖顶形态等），那么市场见顶或见底的机会就更大了。</p><h3 id="向上跳空和向下跳空并列阴阳线形态" tabindex="-1"><a class="header-anchor" href="#向上跳空和向下跳空并列阴阳线形态" aria-hidden="true">#</a> 向上跳空和向下跳空并列阴阳线形态</h3><figure><img src="'+S+'" alt="image-20240124002953888" tabindex="0" loading="lazy"><figcaption>image-20240124002953888</figcaption></figure><p>向上跳空并列黑白蜡烛线形态（或者称为向上跳空并列阴阳线形态，如图7.14所示）也是一种持续形态。</p><p>市场本处于上升趋势中。这时，出现了一根向上跳空的白色蜡烛线。在这根白色蜡烛线后，紧跟着另一根黑色的蜡烛线。这根黑色蜡烛线的开市价位于前一个白色实体之内，收市价位于前一个白色实体之下。在这样的情况下，这根黑色蜡烛线的收市价就构成了一个买入点。如果在市场回头填补了这里的跳空（即关闭了该窗口）后，抛售压力依然很明显的话，那么这个向上跳空并列黑白蜡烛线形态的看涨意义就不再成立了。在向下跳空并列黑白蜡烛线形态（也称为向下跳空并列阴阳线形态，如图7.15所示）中，基本概念与上述形态是相同的。只不过方向相反。在向上跳空和向下跳空并列黑白蜡烛线形态中，两根蜡烛线实体的大小应当不相上下。这两种并列黑白线跳空形态都很少见。</p><h3 id="高价位和低价位跳空突破形态" tabindex="-1"><a class="header-anchor" href="#高价位和低价位跳空突破形态" aria-hidden="true">#</a> 高价位和低价位跳空突破形态</h3><figure><img src="'+V+'" alt="image-20240124003057985" tabindex="0" loading="lazy"><figcaption>image-20240124003057985</figcaption></figure><p>在上升趋势中，当市场经历了一两个急剧上涨的交易日后，在正常情况下都需要一个调整消化的过程。有时，这个整理过程是通过一系列小实体来完成的。如果在一根坚挺的蜡烛线之后，出现了一群小实体的蜡烛线，则表明市场已经变得犹豫不决了。然而，一旦后来某一天的开市价从这群小实体处向上跳空（也就是说，形成了一个窗口），那么买进的时机就成熟了。这就是一个高价位跳空突破形态（如图7.17所示）。之所以这样称呼这类形态，是因为在这类形态中，市场先是在最近形成的高价位上徘徊，后来才下定决心向上跳空。</p><p>低价位跳空奕破形态正是高价位跳空突破形态的反面角色，两者形态对等而意义相反。低价位跳空突破形态（如图7.18所示）是一个向下跳空的窗口，是从一个低价位的横向密集区处向下打开的。这个横向密集区（一系列较小的实体）发生在一两个急剧下跌的交易日之后，曾经使市场稳定下来。起初，从这群小实体蜡烛线的外观看来，似乎市场正在构筑一个底部。但是后来，市场以窗口的形式从这个密集区向下突破，打消了这种看涨的念头。</p><p>在跳空突破形态中，调整过程不应当超过11个时间单位。</p><h3 id="跳空并列白色蜡烛线形态" tabindex="-1"><a class="header-anchor" href="#跳空并列白色蜡烛线形态" aria-hidden="true">#</a> 跳空并列白色蜡烛线形态</h3><figure><img src="'+X+'" alt="image-20240124003408396" tabindex="0" loading="lazy"><figcaption>image-20240124003408396</figcaption></figure><p>在上升趋势中，先出现了一根向上跳空的白色蜡烛线，随后又是一根白色蜡烛线，并且后面这根线与前一根大小相当，两者的开市价也差不多处在同样的水平上，这样就形成了一种看涨的持续形态。这种二蜡烛线形态称为向上跳空并列白色蜡烛线形态（或者称为向上跳空并列阳线形态，如图7.22所示）。如果市场收市在并列白色蜡烛线的最高点之上，则意味着下一波上涨行情即将展开。</p><p>向下跳空的两根并列白色蜡烛线。这类形态称为向下跳空并列白色蜡烛线形态（如图7.23所示）。在下降趋势中，这类并列的白色蜡烛线也构成了一个持续形态。这就是说，当这类形态出现时，价格将继续走低。为什么这种形态不是看涨的（正如在向上跳空的形态中那样），而是看跌的呢？<strong>这是因为在下降的市场中，这两根白色蜡烛线是由空头平仓过程造成的。一旦空头平仓的过程完成了，价格就要进一步下跌。</strong></p><h3 id="上升三法和下降三法形态" tabindex="-1"><a class="header-anchor" href="#上升三法和下降三法形态" aria-hidden="true">#</a> 上升三法和下降三法形态</h3><figure><img src="'+Y+'" alt="image-20240124003509886" tabindex="0" loading="lazy"><figcaption>image-20240124003509886</figcaption></figure><p>所谓三法形态，包括看涨的上升三法，以及看跌的下降三法。这两类形态均属于持续形态。</p><p>上升三法形态的判别标准，包括以下几个方面：</p><p>1.首先出现的是一根长长的白色蜡烛线。</p><p>2.在这根白色蜡烛线之后，紧跟着一群依次下降的小实体蜡烛线。这群小实体蜡烛线的理想的数目是3根，但是如果比3根再多1、2根，也是可以接受的，条件是，<strong>这群小实体蜡烛线基本上都局限在前面那根长长的白色蜡烛线的价格范围之内</strong>。我们不妨作这样的理解：由于这群较小的蜡烛线均处于第一天的价格范围之内，它们与最前面的长蜡烛线一道，构成了一种类似于三日孕线形态的价格形态（在本形态中，所谓处于最前面的蜡烛线的价格范围之内，指的是这群小蜡烛线均处于该蜡烛线的上下影线的范围之内；而在真正的孕线形态中，仅仅是小蜡烛线的实体包含在前面那根蜡烛线的实体之内）。小蜡烛线既可以是白色的，也可以是黑色的，不过，黑色蜡烛线最常见。</p><p>3.最后一天应当是一根具有坚挺的白色实体的蜡烛线，并且它的收市价市高于第一天的收市价。同时，最后这根蜡烛线的开市价也应当高于前一天的收市价。</p><p>下降三法形态与上升三法形态在图形上完全是对等的，只不过方向相反而已。这类形态的形成过程如下：市场应当处在下降趋势中，首先出场的是一根长长的黑色蜡烛线。在这根黑色蜡烛线之后，跟随着大约三根依次上升的小蜡烛线（通常，它们都是白色的），并且这群蜡烛线的实体统统局限在第一根蜡烛线的范围之内（包括其上、下影线）。最后一天，开市价应低于前一天的收市价，并且收市价应低于第一根黑色蜡烛线的收市价。当最后这根黑色蜡烛线形成后，市场便会向下滑落。</p><p>实战经验：</p><p>1.上升三发中，如果头、尾两根白色（黑色）蜡烛线的交易量超过了中间那群小蜡烛线的交易量，那么，该形态的分量就更重了。</p><p>2.中间的小蜡烛也可能是两根。</p><p>3.不要在价格形态的演变过程中过早采取行动。一定要等到价格形态确实已经完成时，或者得到了其它信号的验证后，才能按照其预测意义采取行动。</p><h3 id="前进白色三兵形态" tabindex="-1"><a class="header-anchor" href="#前进白色三兵形态" aria-hidden="true">#</a> 前进白色三兵形态</h3><figure><img src="'+Z+'" alt="image-20240124004125714" tabindex="0" loading="lazy"><figcaption>image-20240124004125714</figcaption></figure><p>人们把这种形态称为前进白色三兵形态（如图7.36所示），或者更简洁一点，叫作白色三兵形态。本形态由接连出现的三根白色蜡烛线组成，它们的收市价依次上升。当市场在某个低价位稳定了一段时间后，如果出现了这样的形态，就标志着市场即将转强。</p><p>白色三兵形态表现为一个逐渐而稳定的上升过程，其中每根白色蜡烛线的开市价都处于前一天的白色实体之内，或者处在其附近的位置上；每一根白色蜡烛线的收市价都应当位于当日的最高点或接近当日的最高点。这是一种很稳健的市场攀升方式（不过，如果这些白色蜡烛线伸展得过长，那么我们也应当对市场的超买状态有所戒备）。</p><p>果其中第二根和第三根蜡烛线，或者仅仅是第三根蜡烛线，表现出上涨势头减弱的迹向，就构成了一个前方受阻（白色三兵）形态（如图7.37所示）。这就意味着这轮上涨行情碰到了麻烦，持有多头头寸者应当采取一些保护性措施。特别是在上升趋势已经处于晚期阶段时，如果出现了前方受阻形态，则更得多加小心。在前方受阻形态中，作为上涨势头减弱的具体表现，既可能是其中的白色实体一个比一个小，也可能是后两根白色蜡烛线具有相对较长的上影线。</p><p>如果在后两根蜡烛线中，前一根为长长的白色实体，并且向上创出了新高，后一根只是一个小的白色蜡烛线，那么就构成了一个（白色三兵）停顿形态（如图7.38所示）。有时候，这种形态也称为（白色三兵）深思形态。当这一形态出现时，说明牛方的力量至少暂时已经消耗尽了。在本形态中，最后一根小的白色蜡烛线既可能从前一根长长的白色蜡烛线向上跳空（在这种情况，该蜡烛线就变成了一根星线），也可能如同日本分析师所描述的那样，“骑在那根长长的白色蜡烛线实体的肩上”（这就是说，位于前一根长的白色实体的上端）。这根小小的实体暴露了牛方能量的衰退。当停顿形态发生时，便构成了多头头寸平仓获利的紧要时机。</p><p>虽然前方受阻形态与停顿形态在一般情况下都不属于顶部反转形态，但是有时候，它们也能引出不容忽视的下跌行情。我们应当利用前方受阻形态和停顿形态来平仓了结已有的多头头寸，或者为多头头寸采取保护措施（比如说，卖出与多头头寸相当的买权期权合约），但是不可据之开立空头头寸。一般来说，如果这两类形态出现在较高的价格水平上，则更有预测意义。</p><h3 id="分手蜡烛线形态" tabindex="-1"><a class="header-anchor" href="#分手蜡烛线形态" aria-hidden="true">#</a> 分手蜡烛线形态</h3><figure><img src="'+q+'" alt="image-20240124004540283" tabindex="0" loading="lazy"><figcaption>image-20240124004540283</figcaption></figure><p>反击线形态是一种二蜡烛线形态，前后两根蜡烛线颜色相反，并且后一根蜡烛线的收市价与前一根的收市价处于同一水平。这一形态属于反转信号。如图7.42所示的分手线形态也是由两根颜色相反的蜡烛线组成的，但是同反击线形态不同的是，分手线形态的两根蜡烛线具有相同的开市价。分手蜡烛线形态属于持续信号。</p><h2 id="神奇的十字线" tabindex="-1"><a class="header-anchor" href="#神奇的十字线" aria-hidden="true">#</a> 神奇的十字线</h2><p>十字线是一类特别的蜡烛线，其开市价与收市价处在同一个水平上。是一种极其重要的反转信号。</p><figure><img src="'+w+'" alt="image-20240124004802531" tabindex="0" loading="lazy"><figcaption>image-20240124004802531</figcaption></figure><h3 id="十字线的重要性" tabindex="-1"><a class="header-anchor" href="#十字线的重要性" aria-hidden="true">#</a> 十字线的重要性</h3><p>在一根完美的十字线上，开市价与收市价处于同一水平，不过，这一标准也有一定程度的灵活性。</p><p>如果当时市场正处在一个重要的转折点，或者正处在牛市或熊市的晚期阶段，或者当时已经有其它技术信号发出了警告信息，那么，此时出现的近似十字线就应当看成一根十字线。</p><p>十字线是一种不同凡响的趋势反转信号。如果十字线之后的蜡烛线发出了验证信号，证实了它的反转信号的话，就进一步加大了趋势反转的可能性。需要指出的是，只有在一个市场不经常出现十字线的条件下，十字线才具有重要意义。</p><h3 id="市场顶部的十字线" tabindex="-1"><a class="header-anchor" href="#市场顶部的十字线" aria-hidden="true">#</a> 市场顶部的十字线</h3><figure><img src="'+A+'" alt="image-20240126003157571" tabindex="0" loading="lazy"><figcaption>image-20240126003157571</figcaption></figure><p>十字线之所以极有价值，是因为它在揭示市场顶部方面有过人之长。在市场经历了长期的上涨之后，或者当市场处于超买状态时，如果出现了一根十字线，则意味着买方搭起来的脚手架马上就要垮掉了。</p><p>当十字线出现时，在上升趋势中，市场可能向下反转，而在下降趋势中，市场则可能继续下跌。由于市场参与者抱着骑墙的态度，市场往往因为自身的重力而下坠，十字线在构成底部反转信号时，比作为顶部反转信号需要更多的佐证。</p><p><strong>实战经验：</strong></p><p>1.所谓长腿十字线，指某根十字线具有一条或两条很长的影线。长腿十字线经常构成市场顶部信号。</p><p>2.十字线作为顶部反转信号与作为底部反转信号，两种情况比起来，前一种情况往往只需要较少的验证信号。</p><p>3.如果在十字线之后还有其它验证信号，就提高了预测趋势反转的成功机会。</p><p>4.如果十字线出现在一根长长的白色蜡烛线之后，特别是在十字线发生在长期的上升趋势之后的情况下，常常构成了一个顶部将临的预警信号。</p><h3 id="长腿十字线和黄包车夫" tabindex="-1"><a class="header-anchor" href="#长腿十字线和黄包车夫" aria-hidden="true">#</a> 长腿十字线和黄包车夫</h3><figure><img src="'+C+'" alt="image-20240126003716870" tabindex="0" loading="lazy"><figcaption>image-20240126003716870</figcaption></figure><p>位于市场顶部的长腿十字线是一种特别重要的十字线。这类十字线具有长长的上影线和下影线，鲜明地表露出市场举棋不定的心理状态。</p><p>在形成长腿十字线的交易日中，市场先是猛烈地上推、后是急剧地下滑（或者反过来），最后到收市时，其收市价处在与开市价同样的水平，或者与之非常接近。</p><p>如果当日的开市价和收市价正好处在全日价格范围的中点，那么这种蜡烛线就称为黄包车夫（线）。</p><p>如果某根非十字线的蜡烛线具有很长的上影线，或者具有很长的下影线，并且其实体较小，这种蜡烛线就称为风高浪大线。如果出现了一群风高浪大线，也构成了一种反转形态。对日本分析师来说，非常长的上影线或非常长的下影线的形成一一借用他们的话来描述，就表示市场“失去了方向感”。</p><h3 id="墓碑十字线" tabindex="-1"><a class="header-anchor" href="#墓碑十字线" aria-hidden="true">#</a> 墓碑十字线</h3><p>在某根蜡烛线上，当开市价和收市价都位于当日的最低点时，就形成了一根墓碑十字线。位于上涨行情之后的墓碑十字线具有疲软的意义</p><p>虽然我们有时也能够在市场底部发现这类蜡烛线，不过，这类形态最突出的长处还是在于昭示市场顶部方面。</p><figure><img src="'+D+'" alt="image-20240126003854841" tabindex="0" loading="lazy"><figcaption>image-20240126003854841</figcaption></figure><p>墓碑十字线与流星形态颇为相像。发生在市场顶部的墓碑十字线，实际上是流星形态的一种特殊情况。流星蜡烛线具有较小的实体，而墓碑十字线作为一根十字线甚至没有实体。墓碑十字线比流星形态更为疲软。</p><h3 id="构成支撑水平和阻挡水平的十字线" tabindex="-1"><a class="header-anchor" href="#构成支撑水平和阻挡水平的十字线" aria-hidden="true">#</a> 构成支撑水平和阻挡水平的十字线</h3><figure><img src="'+F+'" alt="image-20240126003958853" tabindex="0" loading="lazy"><figcaption>image-20240126003958853</figcaption></figure><p>十字蜡烛线有时候可能转化为一个支撑区或一个阻挡区，特别是当它出现在重要的市场顶部或底部的时候。</p><h3 id="三星形态" tabindex="-1"><a class="header-anchor" href="#三星形态" aria-hidden="true">#</a> 三星形态</h3><figure><img src="'+G+'" alt="image-20240126004034301" tabindex="0" loading="lazy"><figcaption>image-20240126004034301</figcaption></figure><p>三星形态（如图8.19所示）非常罕见，但是是一种意义极其重大的反转形态。三星形态是由三根十字线组成的，中间的十字线是一根十字星蜡烛线。</p><h2 id="蜡烛图技术汇总" tabindex="-1"><a class="header-anchor" href="#蜡烛图技术汇总" aria-hidden="true">#</a> 蜡烛图技术汇总</h2><h3 id="实战1" tabindex="-1"><a class="header-anchor" href="#实战1" aria-hidden="true">#</a> 实战1</h3><figure><img src="'+H+'" alt="image-20240126004342319" tabindex="0" loading="lazy"><figcaption>image-20240126004342319</figcaption></figure><p>1.这是一根看涨的倒锤子线。下一天的开市价较高，并且形成了一根白色蜡烛线，从而验证了倒锤子线的信号。</p><p>2.这是一个停顿形态，意味着当前市场向上的努力已经限入困境。</p><p>3.在上述停顿形态中。最后一根蜡烛线还是一根上吊线，这就为该形态抹上了更深的疲弱色彩。</p><p>4.序号4处的黑色蜡烛线证实了上述上吊线的信号。综合3、4两处，既组成了一个平头顶部形态，也构成了一个看跌吞没形态。</p><p>5.这里又是一根上吊线。</p><p>6.这是一个看涨吞没形态，并且其中后一根蜡烛线是一根坚挺的白色捉腰带线。两方面均意味着上涨行情即将到来。</p><p>7.上述上涨行情一直发展到这根上吊线出现的时候。这几乎是一个理想的上吊线，它具有极长的下影线、小小的实体、几乎没有上影线。在下一天的价格变化中，没有向上的运动，由此验证了这根上吊线的看跌性质。</p><p>8.这是一根倒锤子线，并且下一天的行情验证了它的信号。这根蜡烛线同时也是一个启明星形态的组成部分。</p><p>9.从8处的倒锤子线开始，市场形成了一轮历时三天的上涨行情，到了此处，便为这个孕线形态所中止。</p><p>10.这是一根锤子线，象征着市场底部可能来临了。</p><p>11.这里出现了一个看涨刺透形态的变体。其中第二根白色蜡烛线的开市价本应低于前一天的最低价，但是这里仅低于前一天的收市价。在第二根蜡烛线上，市场开始上涨，其收市价明显地向上穿入到前一天黑色蜡烛线实体的内部。</p><p>12.这里又是一根上吊线。但是这根线的信号在下一天没有得到验证，因为市场在开市时已经向上跳出。</p><p>13.此处出现了一个看跌的吞没形态。</p><p>14.这里形成了一个经典的刺透形态。在本形态中，第二天还是一根坚挺的捉腰带线，并且其收市价位于当日最高点。另外，这根线还成功地向下试探了11处低点的水平。</p><p>15.十字星形态标志眷当前上涨行情的结束。这轮上涨行情开始于14处。</p><p>16.这是一个孕线形态，它导致了之前价格下跌过程的终结。</p><h3 id="实战2" tabindex="-1"><a class="header-anchor" href="#实战2" aria-hidden="true">#</a> 实战2</h3><figure><img src="'+I+'" alt="image-20240126004458694" tabindex="0" loading="lazy"><figcaption>image-20240126004458694</figcaption></figure><p>1.这是一个平头底部形态，并且其中还有一根白色的看涨捉腰带线。</p><p>2.此处为乌云盖顶形态。</p><p>3.一个窗口，意味着此处将构成一个阻挡区。</p><p>4.后来出现了一个启明星形态。这个启明星形态有一个不同寻常之处，其中第三天不是一根长长的白色实体。尽管如此，这根蜡烛线还是明显地向上推进到了第一天的白色蜡烛线之内。另一方面，本启明星形态也是对前一周低点的成功的试探。</p><p>5.从4处开始的上涨行情为此处一个小型平头顶部形态所终结，这个平头顶部形态恰好停止在3处窗口的位置上。</p><p>6.这是一根倒锤子线，它得到了下一天的验证。从这个倒锤子线出发的上涨行情向上推过了上述窗口的阻挡水平。</p><p>7.一个孕线形态，它暂时中断了先前的趋势（在本例中，先前的趋势就是那段上涨行情）。</p><p>8.此处，前一天是一根很大的黑色蜡烛线，但它的疲弱意味已经被后一天的小实体中和掉了。这两根线组成了一个孕线形态。这就表示之前的市场运动（在本例中是一个下降趋势）已经失去了动力。</p><p>9.这是一根锤子线，它出现在8处的孕线形态之后，进一步证明之前的下降趋势已经完结。</p><p>10.此处是一个十字星形态，警告我们顶部就要降临了。</p><p>11.这里是一个孕线形态，构成了另一个警告信号，说明之前的上升趋势已经到头了。</p><p>12.这是一个乌云盖顶形态。字母X（在2月初）、Y（在2月中）、Z（在2月底）所标出的价格变化过程形成了一个三尊顶部形态。</p><p>13.一根锤子线。</p><p>14.又是一个孕线形态。该形态之前的短期上升趋势起源于13处的锤子线，本形态一出现，这段上涨行情就短路了。</p><p>15.这里有两个窗口，它们应起到阻挡作用。</p><p>16.一根倒锤子线。同时，这里也组成了一个平头底部形态。</p><p>17.由上述倒锤子线引发的上涨行情遭到了由15处的窗口形成的阻挡水平的拦截，于是这段行情天折了。</p><p>18.一个孕线形态，它暗示着当前的下降趋势可能已经终结。</p><p>19.这是一个乌云盖顶形态。</p><h3 id="实战3" tabindex="-1"><a class="header-anchor" href="#实战3" aria-hidden="true">#</a> 实战3</h3><figure><img src="'+J+'" alt="image-20240126004601947" tabindex="0" loading="lazy"><figcaption>image-20240126004601947</figcaption></figure><p>1.在5月中旬，出现了一个孕线形态，这就加大了当前上升趋势已经结束的可能性。</p><p>2.6月1日是一根高高的白色蜡烛线，在它后面，是一根较小的白色蜡烛线。于是形成了一个停顿形态。</p><p>3.一个看跌的吞没形态。</p><p>4、5.前头是一根十字线，后头是一根上吊线一一当然不是一种健康的组合。</p><p>6.这也是一根上吊线。</p><p>7.此处的孕线形态表明，市场已经上从上升趋势转入一个犹豫不决的转折点。</p><p>8.紧随着上述孕线形态，出现了一个看跌吞没形态。由此可见，市场的犹豫心理很快就被卖方坚定的信心打消了。这个实例还说明了另一个问题。在这个吞没形态中，因为第二天的黑色蜡烛线并未向上创出新高，所以按照西方技术分析方法，这一天不属于反转日。然而，在蜡烛图技术中，这里却发出了一个很扎眼的反转信号。</p>',319),R=[Q];function T(U,W){return L(),M("div",null,R)}const ta=K(P,[["render",T],["__file","17-读书总结.html.vue"]]);export{ta as default};
